static boolean isSimpleNumber(String s) {
    if (s == null) {
      return false;
    }
    int len = s.length();
    if (len == 0) {
      return false;
    }
    for (int index = 0; index < len; index++) {
      char c = s.charAt(index);
      if (c < '0' || c > '9') {
        return false;
      }
    }
    // Disallow leading zeros for multi-digit numbers (e.g., "010", "00")
    if (len > 1 && s.charAt(0) == '0') {
      return false;
    }
    return true;
  }
